import { Routes } from '@angular/router';
import { authGuard, portalGuard } from './core/guards/auth.guard';
import { FlowRoute } from './flow-meta';

// `data.flow` is the single source of truth for the user-flow graph AND the runtime navbar.
// Every navigable state is URL-addressable (tabs=?tab=, modals=?modal=, panels=?panel=, /:id).
export const routes: Routes = ([
  { path: '', redirectTo: 'login', pathMatch: 'full' },

  // ---- Public auth ----
  {
    path: 'login',
    loadComponent: () => import('./features/login/login.component').then((m) => m.LoginComponent),
    data: { flow: { flowId: 'login', node: 'login', entry: true, edgesTo: ['dashboard', 'signup', 'portal-login'], label: 'Login' } },
  },
  {
    path: 'signup',
    loadComponent: () => import('./features/signup/signup.component').then((m) => m.SignupComponent),
    data: { flow: { flowId: 'signup', node: 'signup', edgesTo: ['dashboard', 'login'], label: 'Sign up' } },
  },
  {
    path: 'portal/login',
    loadComponent: () => import('./features/portal/portal-login/portal-login.component').then((m) => m.PortalLoginComponent),
    data: { flow: { flowId: 'portal-login', node: 'portal-login', edgesTo: ['portal-home', 'login'], label: 'Portal Login' } },
  },

  // ---- Internal app (guarded) ----
  {
    path: '',
    loadComponent: () => import('./components/app-shell/app-shell.component').then((m) => m.AppShellComponent),
    canActivate: [authGuard],
    children: [
      { path: 'dashboard', loadComponent: () => import('./features/dashboard/dashboard.component').then((m) => m.DashboardComponent),
        data: { flow: { flowId: 'dashboard', node: 'dashboard', showInNavbar: true, label: 'Dashboard', scope: 'all', edgesTo: ['accounts', 'email', 'orders', 'tasks'] } } },

      { path: 'accounts', loadComponent: () => import('./features/accounts/accounts.component').then((m) => m.AccountsComponent),
        data: { flow: { flowId: 'accounts', node: 'accounts', showInNavbar: true, label: 'Accounts', edgesTo: ['account-detail'] } } },
      { path: 'accounts/:id', loadComponent: () => import('./features/accounts/account-detail.component').then((m) => m.AccountDetailComponent),
        data: { flow: { flowId: 'account-detail', node: 'account-detail', label: 'Account', edgesTo: ['contact-detail', 'project-detail', 'quotes'] } } },

      { path: 'contacts', loadComponent: () => import('./features/contacts/contacts.component').then((m) => m.ContactsComponent),
        data: { flow: { flowId: 'contacts', node: 'contacts', showInNavbar: true, label: 'Contacts', edgesTo: ['contact-detail'] } } },
      { path: 'contacts/:id', loadComponent: () => import('./features/contacts/contact-detail.component').then((m) => m.ContactDetailComponent),
        data: { flow: { flowId: 'contact-detail', node: 'contact-detail', label: 'Contact', edgesTo: ['account-detail', 'email'] } } },

      { path: 'projects', loadComponent: () => import('./features/projects/projects.component').then((m) => m.ProjectsComponent),
        data: { flow: { flowId: 'projects', node: 'projects', showInNavbar: true, label: 'Projects', edgesTo: ['project-detail'] } } },
      { path: 'projects/:id', loadComponent: () => import('./features/projects/project-detail.component').then((m) => m.ProjectDetailComponent),
        data: { flow: { flowId: 'project-detail', node: 'project-detail', label: 'Project', edgesTo: ['quotes', 'orders'] } } },

      { path: 'design-ins', loadComponent: () => import('./features/design-ins/design-ins.component').then((m) => m.DesignInsComponent),
        data: { flow: { flowId: 'design-ins', node: 'design-ins', showInNavbar: true, label: 'Design-Ins', edgesTo: ['quotes'] } } },

      { path: 'quotes', loadComponent: () => import('./features/quotes/quotes.component').then((m) => m.QuotesComponent),
        data: { flow: { flowId: 'quotes', node: 'quotes', showInNavbar: true, label: 'Quotes', edgesTo: ['quote-detail'] } } },
      { path: 'quotes/:id', loadComponent: () => import('./features/quotes/quote-detail.component').then((m) => m.QuoteDetailComponent),
        data: { flow: { flowId: 'quote-detail', node: 'quote-detail', label: 'Quote', edgesTo: ['validation', 'orders'] } } },

      { path: 'validation', loadComponent: () => import('./features/validation/validation.component').then((m) => m.ValidationComponent),
        data: { flow: { flowId: 'validation', node: 'validation', showInNavbar: true, label: 'Validation', edgesTo: ['quotes'] } } },

      { path: 'orders', loadComponent: () => import('./features/orders/orders.component').then((m) => m.OrdersComponent),
        data: { flow: { flowId: 'orders', node: 'orders', showInNavbar: true, label: 'Orders', edgesTo: ['order-detail'] } } },
      { path: 'orders/:id', loadComponent: () => import('./features/orders/order-detail.component').then((m) => m.OrderDetailComponent),
        data: { flow: { flowId: 'order-detail', node: 'order-detail', label: 'Order', edgesTo: ['warranty'] } } },

      { path: 'warranty', loadComponent: () => import('./features/warranty/warranty.component').then((m) => m.WarrantyComponent),
        data: { flow: { flowId: 'warranty', node: 'warranty', showInNavbar: true, label: 'Warranty', edgesTo: ['orders'] } } },

      { path: 'revenue', loadComponent: () => import('./features/revenue/revenue.component').then((m) => m.RevenueComponent),
        data: { flow: { flowId: 'revenue', node: 'revenue', showInNavbar: true, label: 'Revenue', edgesTo: ['reports'] } } },

      { path: 'forecasting', loadComponent: () => import('./features/forecasting/forecasting.component').then((m) => m.ForecastingComponent),
        data: { flow: { flowId: 'forecasting', node: 'forecasting', showInNavbar: true, label: 'Forecasting', edgesTo: ['design-ins'] } } },

      { path: 'email', loadComponent: () => import('./features/email/email.component').then((m) => m.EmailComponent),
        data: { flow: { flowId: 'email', node: 'email', showInNavbar: true, label: 'Email', edgesTo: ['tasks', 'contact-detail'] } } },

      { path: 'documents', loadComponent: () => import('./features/documents/documents.component').then((m) => m.DocumentsComponent),
        data: { flow: { flowId: 'documents', node: 'documents', showInNavbar: true, label: 'Documents', edgesTo: ['orders'] } } },

      { path: 'tasks', loadComponent: () => import('./features/tasks/tasks.component').then((m) => m.TasksComponent),
        data: { flow: { flowId: 'tasks', node: 'tasks', showInNavbar: true, label: 'Tasks', edgesTo: ['email'] } } },

      { path: 'catalog', loadComponent: () => import('./features/catalog/catalog.component').then((m) => m.CatalogComponent),
        data: { flow: { flowId: 'catalog', node: 'catalog', showInNavbar: true, label: 'Catalog', edgesTo: ['validation'] } } },

      { path: 'reports', loadComponent: () => import('./features/reports/reports.component').then((m) => m.ReportsComponent),
        data: { flow: { flowId: 'reports', node: 'reports', showInNavbar: true, label: 'Reports', edgesTo: ['accounts'] } } },

      { path: 'settings', loadComponent: () => import('./features/settings/settings.component').then((m) => m.SettingsComponent),
        data: { flow: { flowId: 'settings', node: 'settings', showInNavbar: true, label: 'Settings', edgesTo: ['dashboard'] } } },
    ],
  },

  // ---- Customer portal (separately guarded) ----
  {
    path: 'portal',
    loadComponent: () => import('./components/portal-shell/portal-shell.component').then((m) => m.PortalShellComponent),
    canActivate: [portalGuard],
    children: [
      { path: '', loadComponent: () => import('./features/portal/portal-dashboard/portal-dashboard.component').then((m) => m.PortalDashboardComponent),
        data: { flow: { flowId: 'portal-home', node: 'portal-home', label: 'Portal Home', edgesTo: ['portal-orders', 'portal-documents', 'portal-pricing', 'portal-notifications'] } } },
      { path: 'orders', loadComponent: () => import('./features/portal/portal-orders/portal-orders.component').then((m) => m.PortalOrdersComponent),
        data: { flow: { flowId: 'portal-orders', node: 'portal-orders', label: 'Portal Orders', edgesTo: ['portal-order-detail'] } } },
      { path: 'orders/:id', loadComponent: () => import('./features/portal/portal-order-detail/portal-order-detail.component').then((m) => m.PortalOrderDetailComponent),
        data: { flow: { flowId: 'portal-order-detail', node: 'portal-order-detail', label: 'Portal Order', edgesTo: ['portal-orders'] } } },
      { path: 'documents', loadComponent: () => import('./features/portal/portal-documents/portal-documents.component').then((m) => m.PortalDocumentsComponent),
        data: { flow: { flowId: 'portal-documents', node: 'portal-documents', label: 'Portal Documents', edgesTo: ['portal-home'] } } },
      { path: 'pricing-requests', loadComponent: () => import('./features/portal/portal-pricing-requests/portal-pricing-requests.component').then((m) => m.PortalPricingRequestsComponent),
        data: { flow: { flowId: 'portal-pricing', node: 'portal-pricing', label: 'Pricing Requests', edgesTo: ['portal-project'] } } },
      { path: 'project-requests', loadComponent: () => import('./features/portal/portal-project-requests/portal-project-requests.component').then((m) => m.PortalProjectRequestsComponent),
        data: { flow: { flowId: 'portal-project', node: 'portal-project', label: 'Project Requests', edgesTo: ['portal-home'] } } },
      { path: 'notifications', loadComponent: () => import('./features/portal/portal-notifications/portal-notifications.component').then((m) => m.PortalNotificationsComponent),
        data: { flow: { flowId: 'portal-notifications', node: 'portal-notifications', label: 'Notifications', edgesTo: ['portal-home'] } } },
    ],
  },

  { path: '**', redirectTo: 'login' },
] satisfies FlowRoute[]) as Routes;
