import { CanActivateFn, Router } from '@angular/router';
import { inject } from '@angular/core';

const TOKEN_KEY = 'auth_token';

function role(): string | null {
  try {
    const raw = localStorage.getItem('user');
    return raw ? (JSON.parse(raw).role ?? null) : null;
  } catch {
    return null;
  }
}

/** Internal app guard — requires a session and blocks portal (customer) users. */
export const authGuard: CanActivateFn = () => {
  const router = inject(Router);
  const token = localStorage.getItem(TOKEN_KEY);
  if (!token) return router.createUrlTree(['/login']);
  if (role() === 'customer') return router.createUrlTree(['/portal']);
  return true;
};

/** Customer portal guard — requires a session scoped to the customer role. */
export const portalGuard: CanActivateFn = () => {
  const router = inject(Router);
  const token = localStorage.getItem(TOKEN_KEY);
  if (!token) return router.createUrlTree(['/portal/login']);
  if (role() !== 'customer') return router.createUrlTree(['/dashboard']);
  return true;
};
